namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0
        ? Math.Round((double)RatingSum / TotalRatings, 1)
        : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;
    private readonly Lock _lock = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new()
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple yet delicious pizza with fresh tomatoes, mozzarella, and basil.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10–12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 50
            },
            new()
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy Roman pasta with eggs, cheese, and pancetta.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk eggs with grated Pecorino and pepper.", "Toss hot pasta with pancetta.", "Remove from heat, stir in egg mixture quickly.", "Serve immediately with extra cheese."],
                TotalRatings = 8, RatingSum = 35
            },
            new()
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken pieces in a creamy spiced tomato sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or pan-fry chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer.", "Stir in cream and garam masala.", "Add chicken, simmer 10 minutes.", "Serve with basmati rice."],
                TotalRatings = 15, RatingSum = 68
            },
            new()
            {
                Id = 4, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in crispy tortillas with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheese", "Sour cream", "Salsa"],
                Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, and sour cream.", "Serve with salsa on the side."],
                TotalRatings = 10, RatingSum = 42
            },
            new()
            {
                Id = 5, Title = "Pad Thai", Category = "Thai",
                Description = "Stir-fried rice noodles with shrimp, peanuts, and tangy sauce.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Peanuts", "Lime", "Fish sauce", "Tamarind paste", "Sugar"],
                Steps = ["Soak rice noodles in warm water.", "Mix fish sauce, tamarind paste, and sugar for sauce.", "Stir-fry shrimp, set aside.", "Scramble eggs in the same pan.", "Add noodles and sauce, toss to coat.", "Add shrimp and bean sprouts.", "Serve with crushed peanuts and lime wedges."],
                TotalRatings = 9, RatingSum = 40
            },
            new()
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh avocado dip with lime, cilantro, and a kick of jalapeño.",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
                Steps = ["Halve and pit avocados, scoop into a bowl.", "Mash with a fork to desired consistency.", "Stir in diced onion, tomato, and jalapeño.", "Add lime juice and chopped cilantro.", "Season with salt to taste.", "Serve immediately with tortilla chips."],
                TotalRatings = 6, RatingSum = 27
            },
            new()
            {
                Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Rich individual cakes with a molten chocolate center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps = ["Preheat oven to 425°F. Grease ramekins.", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold in chocolate mixture.", "Add flour and vanilla, mix gently.", "Pour into ramekins, bake 12–14 minutes.", "Invert onto plates and serve immediately."],
                TotalRatings = 20, RatingSum = 93
            },
            new()
            {
                Id = 8, Title = "Tom Yum Soup", Category = "Thai",
                Description = "Hot and sour Thai soup with shrimp and aromatic herbs.",
                Ingredients = ["Shrimp", "Lemongrass", "Galangal", "Kaffir lime leaves", "Mushrooms", "Chili paste", "Fish sauce", "Lime juice"],
                Steps = ["Bring water to a boil with lemongrass, galangal, and lime leaves.", "Add mushrooms and chili paste.", "Add shrimp and cook until pink.", "Season with fish sauce and lime juice.", "Serve hot, garnished with cilantro."],
                TotalRatings = 7, RatingSum = 30
            },
        };
        _nextId = 9;
    }

    public List<string> GetCategories()
    {
        lock (_lock)
        {
            return _recipes.Select(r => r.Category).Distinct().Order().ToList();
        }
    }

    public List<Recipe> GetByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public Recipe? GetById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars is < 1 or > 5) return;
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            if (recipe is not null)
            {
                recipe.TotalRatings++;
                recipe.RatingSum += stars;
            }
        }
    }

    public void Submit(RecipeSubmission submission)
    {
        lock (_lock)
        {
            _recipes.Add(new Recipe
            {
                Id = _nextId++,
                Title = submission.Title.Trim(),
                Category = submission.Category.Trim(),
                Description = $"A community-submitted recipe for {submission.Title.Trim()}.",
                Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
                Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            });
        }
    }
}

