@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-warning mb-2">
                            @for (int i = 1; i <= 5; i++)
                            {
                                <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                            }
                            <span class="text-muted ms-1">(@recipe.AverageRating / 5)</span>
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeCommunity.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe")</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-danger">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="lead">@Recipe.Description</p>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h4>Steps</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in Recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-3 mb-4">
        <div class="card-body">
            <h5>Rate this recipe</h5>
            <p class="text-muted">Average: @Recipe.AverageRating / 5 (@Recipe.TotalRatings ratings)</p>
            <StarRating RecipeId="Recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeCommunity.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="d-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-3 text-decoration-none"
                style="color: @(star <= (Submitted ? SubmittedRating : HoveredStar) ? "#ffc107" : "#dee2e6"); cursor: @(Submitted ? "default" : "pointer");"
                @onmouseover="() => Hover(star)"
                @onmouseout="ResetHover"
                @onclick="() => Rate(star)"
                disabled="@Submitted"
                aria-label="@star stars">
            ★
        </button>
    }

    @if (Submitted)
    {
        <span class="text-success ms-2">✓ Thanks! You rated @SubmittedRating star(s).</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int HoveredStar { get; set; }
    private int SubmittedRating { get; set; }
    private bool Submitted { get; set; }

    private void Hover(int star)
    {
        if (!Submitted) HoveredStar = star;
    }

    private void ResetHover()
    {
        if (!Submitted) HoveredStar = 0;
    }

    private void Rate(int star)
    {
        if (Submitted) return;
        RecipeService.AddRating(RecipeId, star);
        SubmittedRating = star;
        Submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>📝 Submit a Recipe</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

@if (IsSubmitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "<strong>@Submission.Title</strong>" has been submitted successfully.
        <a href="/">Back to Home</a>
    </div>
}
else
{
    <div class="card shadow-sm">
        <div class="card-body">
            <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="Submission.Title" placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                        <option value="">-- Select a category --</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                    <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Submission.Ingredients"
                        placeholder="2 cups flour&#10;1 cup sugar&#10;3 apples, peeled and sliced" />
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Steps (one per line)</label>
                    <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Submission.Steps"
                        placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients." />
                </div>

                <button type="submit" class="btn btn-success"
                        disabled="@(string.IsNullOrWhiteSpace(Submission.Title) || string.IsNullOrWhiteSpace(Submission.Category) || string.IsNullOrWhiteSpace(Submission.Ingredients) || string.IsNullOrWhiteSpace(Submission.Steps))">
                    Submit Recipe
                </button>
            </EditForm>
        </div>
    </div>
}

@code {
    private RecipeSubmission Submission { get; set; } = new();
    private bool IsSubmitted { get; set; }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Submission.Title) ||
            string.IsNullOrWhiteSpace(Submission.Category) ||
            string.IsNullOrWhiteSpace(Submission.Ingredients) ||
            string.IsNullOrWhiteSpace(Submission.Steps))
            return;

        RecipeService.Submit(Submission);
        IsSubmitted = true;
    }
}

